mapper.update:
UPDATE internal_tasks
SET status     = #{status},
    version    = version + 1,
    updated_at = NOW()
WHERE id = #{id}
  AND version = #{expectedVersion}

mapper.select:
SELECT DISTINCT it.*
FROM internal_tasks it
INNER JOIN task_recipients tr ON it.id = tr.task_id
WHERE tr.user_id = #{userId}
  AND it.show_on_calendar = 1
  AND it.due_time IS NOT NULL
  AND it.due_time >= #{from}
  AND it.due_time < #{to}
ORDER BY it.due_time ASC
